import { generateText } from "ai";
import { openai } from "@ai-sdk/openai";

const { text, usage } = await generateText({
  model: openai("gpt-4o"),
  prompt: "What is the capital of France?",
});

console.log(text);   // "The capital of France is Paris."
console.log(usage);  // { promptTokens: 15, completionTokens: 9, totalTokens: 24 }

import { generateText } from "ai";
import { openai } from "@ai-sdk/openai";

const { text } = await generateText({
  model: openai("gpt-4o"),
  system: "You are a concise assistant. Reply in one sentence.",
  messages: [
    { role: "user", content: "Explain recursion." },
    { role: "assistant", content: "Recursion is a function that calls itself." },
    { role: "user", content: "Give a Python example." },
  ],
});

console.log(text);

import { streamText } from "ai";
import { openai } from "@ai-sdk/openai";

const result = streamText({
  model: openai("gpt-4o"),
  prompt: "Write a haiku about TypeScript.",
});

// Iterate over the text stream
for await (const chunk of result.textStream) {
  process.stdout.write(chunk);
}

// Or await the full text after streaming completes
const fullText = await result.text;
const tokenUsage = await result.usage;

import { generateObject } from "ai";
import { openai } from "@ai-sdk/openai";
import { z } from "zod";

const { object } = await generateObject({
  model: openai("gpt-4o"),
  schema: z.object({
    title: z.string(),
    rating: z.number().min(1).max(5),
    pros: z.array(z.string()),
    cons: z.array(z.string()),
    summary: z.string(),
  }),
  prompt: "Write a product review for a mechanical keyboard.",
});

console.log(object.title);   // typed as string
console.log(object.rating);  // typed as number

import { streamObject } from "ai";
import { openai } from "@ai-sdk/openai";
import { z } from "zod";

const { partialObjectStream } = streamObject({
  model: openai("gpt-4o"),
  schema: z.object({ items: z.array(z.string()) }),
  prompt: "List 5 programming languages with a brief description each.",
});

for await (const partial of partialObjectStream) {
  console.clear();
  console.log(partial.items ?? []);   // incremental array as items are generated
}

import { generateText } from "ai";
import { anthropic } from "@ai-sdk/anthropic";
import { google }    from "@ai-sdk/google";
import { mistral }   from "@ai-sdk/mistral";
import { groq }      from "@ai-sdk/groq";

// Swap providers by changing one line — identical call signature:
await generateText({ model: anthropic("claude-3-5-sonnet-20241022"), prompt: "Hello" });
await generateText({ model: google("gemini-1.5-pro"),                prompt: "Hello" });
await generateText({ model: mistral("mistral-large-latest"),         prompt: "Hello" });
await generateText({ model: groq("llama-3.1-70b-versatile"),         prompt: "Hello" });

// app/api/chat/route.ts — Next.js edge route
import { streamText } from "ai";
import { openai } from "@ai-sdk/openai";

export async function POST(req: Request) {
  const { messages } = await req.json();
  const result = streamText({
    model: openai("gpt-4o"),
    messages,
  });
  return result.toDataStreamResponse();
}

// components/Chat.tsx
"use client";
import { useChat } from "ai/react";

export default function Chat() {
  const { messages, input, handleInputChange, handleSubmit } = useChat();
  return (
    <div>
      {messages.map(m => (
        <p key={m.id}><b>{m.role}:</b> {m.content}</p>
      ))}
      <form onSubmit={handleSubmit}>
        <input value={input} onChange={handleInputChange} placeholder="Message…" />
        <button type="submit">Send</button>
      </form>
    </div>
  );
}

import { wrapLanguageModel, extractReasoningMiddleware } from "ai";
import { openai } from "@ai-sdk/openai";

// Add chain-of-thought extraction to any model
const modelWithReasoning = wrapLanguageModel({
  model: openai("gpt-4o"),
  middleware: extractReasoningMiddleware({ tagName: "think" }),
});

const { text, reasoning } = await generateText({
  model: modelWithReasoning,
  prompt: "What is 17 × 23?",
});

console.log(reasoning);  // chain-of-thought steps
console.log(text);       // final answer

import { embed, embedMany, cosineSimilarity } from "ai";
import { openai } from "@ai-sdk/openai";

const embeddingModel = openai.embedding("text-embedding-3-small");

// Single embedding
const { embedding } = await embed({
  model: embeddingModel,
  value: "The quick brown fox",
});

// Batch embeddings
const { embeddings } = await embedMany({
  model: embeddingModel,
  values: ["sentence one", "sentence two", "sentence three"],
});

// Cosine similarity between two vectors
const score = cosineSimilarity(embeddings[0], embeddings[1]);
console.log(score);   // 0.0 – 1.0

import { generateText, tool } from "ai";
import { openai } from "@ai-sdk/openai";
import { z } from "zod";

const { text, toolCalls, toolResults } = await generateText({
  model: openai("gpt-4o"),
  tools: {
    getWeather: tool({
      description: "Get the current weather for a city.",
      parameters: z.object({
        city: z.string().describe("The city name"),
      }),
      execute: async ({ city }) => {
        return { temperature: 22, condition: "Sunny", city };
      },
    }),
  },
  prompt: "What's the weather in Tokyo and Berlin?",
});

// toolResults contains the executed tool outputs
for (const result of toolResults) {
  console.log(result.toolName, result.result);
}

import { generateText } from "ai";
import { openai } from "@ai-sdk/openai";

const controller = new AbortController();

// Cancel after 5 seconds
setTimeout(() => controller.abort(), 5_000);

try {
  const { text } = await generateText({
    model: openai("gpt-4o"),
    prompt: "Write a very long essay on the history of computing.",
    abortSignal: controller.signal,
  });
  console.log(text);
} catch (err) {
  if (err.name === "AbortError") {
    console.log("Generation cancelled.");
  } else {
    throw err;
  }
}

import { generateText } from "ai";
import { openai } from "@ai-sdk/openai";
import { RetryError } from "ai";

// maxRetries defaults to 2; set to 0 to disable
const { text } = await generateText({
  model: openai("gpt-4o"),
  prompt: "Hello",
  maxRetries: 3,       // retry on 429 and 5xx errors
});

// Custom error handling
try {
  await generateText({ model: openai("gpt-4o"), prompt: "Hello" });
} catch (err) {
  if (err instanceof RetryError) {
    console.log("All retries failed:", err.cause);
  }
}
